This bug is fixed in Tornado 6.5.6. `max_body_size` is now checked both for the compressed and cumulative decompressed size of the response.

Prior to upgrading, this issue can be mitigated by setting `decompress_response=False` or using `CurlAsyncHTTPClient`.", "epss": {"percentage": 0.00691, "percentile": 0.48654}, "ghsa_id": "GHSA-mgf9-4vpg-hj56", "github_reviewed_at": "2026-06-15T20:19:28Z", "html_url": "https://github.com/advisories/GHSA-mgf9-4vpg-hj56", "identifiers": [{"type": "GHSA", "value": "GHSA-mgf9-4vpg-hj56"}, {"type": "CVE", "value": "CVE-2026-49855"}], "nvd_published_at": null, "published_at": "2026-06-15T20:19:28Z", "references": ["https://github.com/tornadoweb/tornado/security/advisories/GHSA-mgf9-4vpg-hj56", "https://github.com/advisories/GHSA-mgf9-4vpg-hj56"], "repository_advisory_url": "https://api.github.com/repos/tornadoweb/tornado/security-advisories/GHSA-mgf9-4vpg-hj56", "severity": "high", "source_code_location": "https://github.com/tornadoweb/tornado", "summary": "tornado AsyncHTTPClient accumulates decompressed chunks without size limit (gzip bomb)", "type": "reviewed", "updated_at": "2026-06-15T20:20:20Z", "url": "https://api.github.com/advisories/GHSA-mgf9-4vpg-hj56", "vulnerabilities": [{"first_patched_version": "6.5.6", "package": {"ecosystem": "pip", "name": "tornado"}, "vulnerable_functions": [], "vulnerable_version_range": "< 6.5.6"}], "withdrawn_at": null}
